import{_ as o,c as r,o as a,a3 as n}from"./chunks/framework.CTM16EAR.js";const c=JSON.parse('{"title":"PWA 快速安装","description":"浏览器访问与 PWA 安装、白屏与缓存、登录与离线、导入导出与第一次使用；桌面安装包见《快速开始》。","frontmatter":{"title":"PWA 快速安装","description":"浏览器访问与 PWA 安装、白屏与缓存、登录与离线、导入导出与第一次使用；桌面安装包见《快速开始》。"},"headers":[],"relativePath":"pwa-getting-started.md","filePath":"pwa-getting-started.md","lastUpdated":1775185454000}'),s={name:"pwa-getting-started.md"};function e(l,t,i,g,d,h){return a(),r("div",null,t[0]||(t[0]=[n('<h1 id="pwa-快速安装" tabindex="-1">PWA 快速安装 <a class="header-anchor" href="#pwa-快速安装" aria-label="Permalink to &quot;PWA 快速安装&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">本文档管什么</p><p><strong>只管</strong>：打开 <a href="https://pomotention.pages.dev" target="_blank" rel="noreferrer">https://pomotention.pages.dev</a>、<strong>安装 PWA</strong>、<strong>白屏 / 加载慢</strong>、登录或离线、<strong>JSON 导入导出</strong>、卸载与清数据、<strong>第一次点哪里</strong>。</p><p><strong>不管</strong>：下载 <strong>.msi / .dmg</strong>、Windows/macOS <strong>系统要求</strong>、桌面端 <strong>自动更新开关</strong> —— 这些在 <a href="./getting-started.html">快速开始（桌面客户端）</a>。</p></div><blockquote><p><strong>目标</strong>：5 分钟内完成「能打开 → 可选装 PWA → 可选导入数据 → 第一次记录」<br><strong>与安装包版本对齐</strong>：当前文档撰写时对应 <strong>v0.6.4</strong>（功能以线上为准）</p></blockquote><h2 id="_1-推荐使用方式-pwa" tabindex="-1">1. 推荐使用方式（PWA） <a class="header-anchor" href="#_1-推荐使用方式-pwa" aria-label="Permalink to &quot;1. 推荐使用方式（PWA）&quot;">​</a></h2><ul><li><p><strong>网页版</strong>：新版本在站点发布后，一般刷新页面即可；若界面异常可尝试强制刷新或清除该站点的浏览数据（与浏览器实现有关）。 <strong>最推荐</strong>：使用浏览器将网页安装为 <strong>PWA</strong>（Progressive Web App），再以独立应用形式打开。</p></li><li><p>访问：<a href="https://pomotention.pages.dev" target="_blank" rel="noreferrer">https://pomotention.pages.dev</a></p></li><li><p>支持 <strong>Service Worker 离线</strong>（在无网或弱网下仍可能打开已缓存的页面）</p></li><li><p>数据主要保存在本地（如 <code>localStorage</code> 等），与是否登录云端无关</p></li></ul><h2 id="_2-安装步骤-按平台" tabindex="-1">2. 安装步骤（按平台） <a class="header-anchor" href="#_2-安装步骤-按平台" aria-label="Permalink to &quot;2. 安装步骤（按平台）&quot;">​</a></h2><h3 id="电脑-edge-chrome-safari" tabindex="-1">电脑：Edge / Chrome / Safari <a class="header-anchor" href="#电脑-edge-chrome-safari" aria-label="Permalink to &quot;电脑：Edge / Chrome / Safari&quot;">​</a></h3><ol><li>浏览器打开 <a href="https://pomotention.pages.dev" target="_blank" rel="noreferrer">https://pomotention.pages.dev</a></li><li>在地址栏或菜单中找到 <strong>「安装应用」</strong> / <strong>「安装 Pomotention」</strong> 等入口并完成安装</li></ol><p><strong>常见差异</strong>：</p><ul><li><strong>Windows</strong>（Edge / Chrome）：通常会明确询问「是否安装此应用」</li><li><strong>macOS 14+（Safari）</strong>：支持直接安装并保存到 Dock</li><li><strong>macOS 13.7.8（实测）</strong>：Safari 入口能力受限，建议安装 <strong>Edge</strong> 后使用其 PWA 安装入口</li></ul><blockquote><p>已验证环境：macOS 13.7.8 可通过 Edge 安装 PWA；更高版本请以浏览器当前提示为准。</p></blockquote><h3 id="手机" tabindex="-1">手机 <a class="header-anchor" href="#手机" aria-label="Permalink to &quot;手机&quot;">​</a></h3><ul><li><strong>iPhone / iPad</strong>（Safari）：分享 → <strong>添加到主屏幕</strong></li><li><strong>Android</strong>（Chrome 等）：菜单 → <strong>添加到主屏幕</strong> 或 <strong>安装应用</strong></li></ul><p>未在文档中单独列出的系统，只要浏览器支持 PWA，理论上也可用类似方式安装，以浏览器实际提示为准。</p><h2 id="pwa-white-screen" tabindex="-1">3. 页面白屏或一直加载不出来 <a class="header-anchor" href="#pwa-white-screen" aria-label="Permalink to &quot;3. 页面白屏或一直加载不出来 {#pwa-white-screen}&quot;">​</a></h2><p>若遇到 <strong>白屏、长时间空白、内容不出现</strong>，可按顺序尝试：</p><ol><li><strong>普通刷新</strong>：<code>F5</code> / 刷新按钮；mac 上常用 <code>Command + R</code></li><li><strong>强制刷新（绕过缓存）</strong>：<code>Command + Shift + R</code>（mac）或 <code>Ctrl + Shift + R</code>（Windows）</li><li><strong>清空本站缓存后再打开</strong>：在浏览器设置中清除 <strong>本站数据</strong> 或 <strong>缓存</strong>（你遇到的 mac 白屏，在清空缓存后恢复，即属此类）</li><li>若使用的是 <strong>从图标打开的 PWA</strong>，可暂时用 <strong>浏览器标签页</strong> 打开同一网址对比是否正常，以区分是否为安装实例的缓存问题</li></ol><h3 id="网络受限场景-需要代理" tabindex="-1">网络受限场景（需要代理） <a class="header-anchor" href="#网络受限场景-需要代理" aria-label="Permalink to &quot;网络受限场景（需要代理）&quot;">​</a></h3><p>有用户反馈：<strong>不翻墙打不开，翻墙后可打开</strong>。这通常说明首次资源请求被网络拦截或超时。</p><ul><li>建议先在可访问网络下（例如开启代理）完成一次完整打开</li><li>等页面加载完成后，再按正常方式安装/打开 PWA</li><li>首次缓存成功后，后续在离线或弱网场景下通常仍可打开已缓存内容（受缓存是否完整影响）</li></ul><div class="tip custom-block"><p class="custom-block-title">PWA 与「普通网页标签」不是同一份存储</p><p>在多数浏览器里，<strong>同一网址在「仅标签页打开」与「已安装的 PWA」</strong> 可能对应 <strong>不同的站点存储分区</strong>（例如 <code>localStorage</code> 等不互通）。<br> 因此：<strong>换了一种打开方式，可能像「另一份本地数据」</strong>；固定一种主要使用方式（推荐已安装的 PWA）可减少困惑。</p></div><h2 id="_4-登录、注册失败与离线使用" tabindex="-1">4. 登录、注册失败与离线使用 <a class="header-anchor" href="#_4-登录、注册失败与离线使用" aria-label="Permalink to &quot;4. 登录、注册失败与离线使用&quot;">​</a></h2><ul><li><strong>能注册 / 登录</strong>：可选用云端同步（依赖与 Supabase 的连接）。</li><li><strong>无法注册或连不上服务器</strong>：仍可使用 <strong>离线模式</strong>；核心数据会落在 <strong>本机</strong>。</li></ul><p>具体按钮文案以当前版本界面为准（例如「跳过」「离线使用」等）。</p><h2 id="_5-数据导出与导入-搬家" tabindex="-1">5. 数据导出与导入（搬家） <a class="header-anchor" href="#_5-数据导出与导入-搬家" aria-label="Permalink to &quot;5. 数据导出与导入（搬家）&quot;">​</a></h2><p>格式为 <strong>JSON</strong>，导入导出在测试流程中已通过验证。</p><h3 id="老版本迁移说明-v0-4-4" tabindex="-1">老版本迁移说明（v0.4.4） <a class="header-anchor" href="#老版本迁移说明-v0-4-4" aria-label="Permalink to &quot;老版本迁移说明（v0.4.4）&quot;">​</a></h3><ul><li>在 <strong>v0.4.4</strong> 中，可进入 <strong>帮助页</strong>，使用 <strong>数据同步</strong> 按钮执行<strong>全量数据导出</strong></li><li>导出的 JSON 文件可直接用于新版本的数据迁移</li></ul><p><strong>导出（备份）</strong>：</p><ol><li>打开 <strong>设置</strong></li><li>使用 <strong>数据导出</strong>，保存得到的 JSON 文件（请自行保管好文件）</li></ol><p><strong>导入</strong>：</p><ol><li>打开 <strong>设置</strong> → <strong>数据导入</strong></li><li>选择此前导出的 JSON 文件并按提示完成</li></ol><div class="warning custom-block"><p class="custom-block-title">导入前建议先导出当前数据</p><p>若当前设备上已有数据，导入可能覆盖或与现有数据合并，行为以软件内提示为准；重要数据请先 <strong>导出备份</strong>。</p></div><h2 id="_6-卸载、清除本地数据" tabindex="-1">6. 卸载、清除本地数据 <a class="header-anchor" href="#_6-卸载、清除本地数据" aria-label="Permalink to &quot;6. 卸载、清除本地数据&quot;">​</a></h2><h3 id="卸载-pwa-从主屏幕移除" tabindex="-1">卸载 PWA / 从主屏幕移除 <a class="header-anchor" href="#卸载-pwa-从主屏幕移除" aria-label="Permalink to &quot;卸载 PWA / 从主屏幕移除&quot;">​</a></h3><ul><li><strong>Windows</strong>：对已安装的应用图标使用右键 → 卸载（或系统/浏览器提供的卸载入口）</li><li><strong>macOS</strong>：从程序坞或启动台移除应用（与浏览器/PWA 实现有关，以系统提示为准）</li><li><strong>手机</strong>：长按主屏幕图标 → 删除应用 / 移除</li></ul><h3 id="完全删除本地数据并重新开始" tabindex="-1">完全删除本地数据并重新开始 <a class="header-anchor" href="#完全删除本地数据并重新开始" aria-label="Permalink to &quot;完全删除本地数据并重新开始&quot;">​</a></h3><ol><li>在应用内打开 <strong>设置</strong></li><li>使用 <strong>清除所有本地数据</strong> / <strong>重置</strong> 类功能（名称以界面为准）</li><li>确认前请 <strong>务必先导出</strong> 需要保留的 JSON</li></ol><p>若仅想解决缓存导致的显示异常，优先使用 <strong>第 3 节</strong> 的刷新与清缓存，不一定需要清空全部数据。</p><h2 id="_7-第一次使用-功能层面-约-2-分钟" tabindex="-1">7. 第一次使用（功能层面，约 2 分钟） <a class="header-anchor" href="#_7-第一次使用-功能层面-约-2-分钟" aria-label="Permalink to &quot;7. 第一次使用（功能层面，约 2 分钟）&quot;">​</a></h2><ol><li>创建或选择一个 <strong>活动</strong></li><li>把它放进 <strong>今日 / 当日计划</strong>（以你界面中的模块为准）</li><li>启动 <strong>番茄计时</strong>，完成一小段专注</li><li>按需记录状态（如精力、愉悦等，若当前版本提供）</li></ol><p>完成后可继续在侧边栏 <strong>「使用说明」</strong> 中按模块深入阅读。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/pomotention/pc-getting-started.html">桌面客户端快速开始</a> — <strong>安装包、系统要求、更新与安装类问题</strong></li><li><a href="/pomotention/guide/">使用说明总览</a> — 界面与各模块详解</li><li><a href="./get-things-done.html">快速使用</a></li></ul>',44)]))}const u=o(s,[["render",e]]);export{c as __pageData,u as default};
